-- Generated by scripts/seed-players.ts. Re-run `npm run seed:players` to refresh.
-- Idempotent: ON CONFLICT updates the row. Assumes seed.sql (teams) ran first.
-- Players are stored with is_in_official_roster=false. The admin flips them via
-- the Lock Rosters action once FIFA's lists are official.

on conflict (external_id) do update set
  team_id = excluded.team_id,
  name = excluded.name,
  position = excluded.position,
  jersey_number = excluded.jersey_number;
